#include <vector>
#include <unordered_map>
#include <climits>

long long solve(std::vector<long long> nums, long long k) {
    std::unordered_map<long long, int> mod_counts;
    long long prefix_mod = 0;
    mod_counts[0] = 1;

    for (long long num : nums) {
        prefix_mod = (prefix_mod + num) % k;
        mod_counts[prefix_mod] += 1;
    }

    long long min_sum = LONG_MAX;
    for (const auto& [mod, count] : mod_counts) {
        min_sum = std::min(min_sum, (k - mod) * count);
    }

    return min_sum;
}
